Adaptive nearest-k insertion with cost-to-distance scoring and exhaustive fallback ensures all orders are assigned optimally without skipping.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	numOrders := len(oris)
	var topK int
	if numOrders <= 5 {
		topK = 3
	} else if numOrders <= 10 {
		topK = 4
	} else {
		topK = 5
	}

	for jj := 0; jj < numOrders; jj++ {
		// Build top-K nearest non-empty assigns based on distance from their current station to origin
		topDist := make([]float64, topK)
		topIdx := make([]int, topK)
		topLen := 0
		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			if dispatch.Assigns[ii].StationsLen <= 0 {
				continue
			}
			dist := cal_dis(dispatch.Assigns[ii].StationCurrent, oris[jj])
			pos := topLen
			if pos >= topK {
				pos = topK - 1
				if dist >= topDist[pos] {
					continue
				}
			} else {
				topLen++
			}
			for pos > 0 && dist < topDist[pos-1] {
				topIdx[pos] = topIdx[pos-1]
				topDist[pos] = topDist[pos-1]
				pos--
			}
			topIdx[pos] = ii
			topDist[pos] = dist
		}
		candidatesTop := topIdx[:topLen]

		// Score candidates: marginal cost increase + distance penalty
		bestIdx := -1
		bestScore := 1e18
		for _, ii := range candidatesTop {
			oldCost := dispatch.Assigns[ii].Cost
			if !dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
				continue
			}
			dispatch.Assigns[ii].GenRoute()
			newCost := dispatch.Assigns[ii].Cost
			if newCost >= 0 {
				dist := cal_dis(dispatch.Assigns[ii].StationCurrent, oris[jj])
				score := (newCost - oldCost) + 0.05*dist
				if score < bestScore {
					bestScore = score
					bestIdx = ii
				}
			}
			dispatch.Assigns[ii].RemoveShip(total_ship + jj)
			dispatch.Assigns[ii].GenRoute()
		}

		if bestIdx != -1 {
			dispatch.Assigns[bestIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
			dispatch.Assigns[bestIdx].GenRoute()
			// bestIdx is always within existing AssignsLen here, so no need to expand
			continue
		}

		// Exhaustive fallback: try all existing assigns and a new one in random order
		fullCand := make([]int, 0, dispatch.AssignsLen+1)
		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			fullCand = append(fullCand, ii)
		}
		if dispatch.AssignsLen < MAXASSIGNS {
			fullCand = append(fullCand, dispatch.AssignsLen)
		}
		rand.Shuffle(len(fullCand), func(i, j int) {
			fullCand[i], fullCand[j] = fullCand[j], fullCand[i]
		})

		inserted := false
		for _, ii := range fullCand {
			if ii >= dispatch.AssignsLen {
				if dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
					dispatch.Assigns[ii].GenRoute()
					if dispatch.Assigns[ii].Cost >= 0 {
						dispatch.AssignsLen = ii + 1
						inserted = true
						break
					}
					dispatch.Assigns[ii].RemoveShip(total_ship + jj)
					dispatch.Assigns[ii].GenRoute()
				}
			} else {
				if !dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
					dispatch.Assigns[ii].Cost = -1 // mark as invalid for safety
				}
				dispatch.Assigns[ii].GenRoute()
				if dispatch.Assigns[ii].Cost >= 0 {
					inserted = true
					break
				}
				dispatch.Assigns[ii].RemoveShip(total_ship + jj)
				dispatch.Assigns[ii].GenRoute()
			}
		}
		if !inserted {
			// order cannot be inserted by any vehicle; still continue to next order
			continue
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

